import type { ObjectOrInterfaceDefinition, SimplePropertyDef, WhereClause } from "@osdk/api";
/**
* A where clause without specific type information - used for runtime matching logic.
* This accepts any WhereClause<T, RDPs> by using the base types.
*/
export type SimpleWhereClause = WhereClause<ObjectOrInterfaceDefinition, Record<string, SimplePropertyDef>>;
